css:
.action-management-print-format {
  font-size: 10.5pt;
  color: #222;
}

.letter-head-wrapper {
  margin-bottom: 18px;
}

.letter-head-wrapper img {
  max-width: 100%;
  height: auto;
}

.print-heading {
  text-align: center;
  margin-bottom: 24px;
}

.print-heading h2 {
  margin: 0;
  font-size: 18pt;
  font-weight: 700;
  letter-spacing: 0.4px;
}

.report-subtitle {
  margin-top: 8px;
  font-size: 11pt;
  line-height: 1.5;
}

table th.table-sr,
table td.table-sr {
  display: none;
}

.kpi-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  border: 1px solid #ddd;
  border-radius: 8px;
  overflow: hidden;
  margin-bottom: 20px;
}

.kpi-table th,
.kpi-table td {
  padding: 8px;
  font-size: 10.5pt;
  vertical-align: top;
}

.kpi-table th {
  background-color: #f5f5f5;
  border-bottom: 1px solid #ddd;
  text-align: left;
  font-weight: 700;
}

.kpi-table td {
  border-bottom: 1px solid #ddd;
  border-right: 1px solid #ddd;
}

.kpi-table td:last-child,
.kpi-table th:last-child {
  border-right: none;
}

.kpi-table tbody tr:last-child td {
  border-bottom: none;
}

.kpi-table tbody tr:nth-child(odd) {
  background-color: #fafafa;
}

.label-cell {
  width: 35%;
  font-weight: 600;
  background-color: #fcfcfc;
}

.text-prewrap {
  white-space: pre-wrap;
}

.attachment-section {
  margin-top: 25px;
}

.attachment-section h3 {
  margin-bottom: 12px;
  font-size: 14pt;
}

.attachment-grid {
  width: 100%;
}

.attachment-card {
  display: inline-block;
  width: 48%;
  margin: 0 1% 18px 1%;
  vertical-align: top;
  text-align: center;
}

.attachment-card img {
  width: 100%;
  max-height: 320px;
  object-fit: contain;
  border: 1px solid #ddd;
  border-radius: 8px;
  padding: 4px;
  background: #fff;
}

.file-card {
  border: 1px solid #ddd;
  border-radius: 8px;
  padding: 14px;
  background: #fff;
  text-align: left;
  min-height: 120px;
}

.attachment-label {
  margin: 0 0 8px 0;
  font-weight: 600;
}

.attachment-link {
  margin: 0;
  word-break: break-word;
}

.attachment-link a {
  color: #222;
  text-decoration: underline;
}

@page {
  @bottom-right {
    content: "Page " counter(page) " of " counter(pages);
    font-size: 10pt;
    color: #999;
  }
}
